.darma-loader-darma-custom-754 {
  color: var(--loader-color, #6366f1);
--s: 15px;
width: calc(var(--s)*2.33);
aspect-ratio: 1;
display: flex;
justify-content: space-between;
animation: darma-loader-darma-custom-754-l29-0 1s infinite;
}
.darma-loader-darma-custom-754::before,
.darma-loader-darma-custom-754::after {
content: "";
width: var(--s);
--_g: no-repeat radial-gradient(farthest-side,currentColor 94%,#0000);
background:
var(--_g) top,
var(--_g) bottom;
background-size: 100% var(--s);
transform-origin: 50% calc(100% - var(--s)/2);
animation: inherit;
animation-name: darma-loader-darma-custom-754-l29-1;
}
.darma-loader-darma-custom-754::after {
--_s:-1;
}
@keyframes darma-loader-darma-custom-754-l29-0 {
100% {transform:translateY(calc(var(--s) - 100%))}
}
@keyframes darma-loader-darma-custom-754-l29-1 {
100% {transform:rotate(calc(var(--_s,1)*-180deg))}
}

